module alu #(
    parameter ADD = 6'b100000,
    parameter ADDU = 6'b100001,
    parameter SUB = 6'b100010,
    parameter SUBU = 6'b100011,
    parameter AND = 6'b100100,
    parameter OR = 6'b100101,
    parameter XOR = 6'b100110,
    parameter NOR = 6'b100111,
    parameter SLT = 6'b101010,
    parameter SLTU = 6'b101011,
    parameter SLL = 6'b000000,
    parameter SRL = 6'b000010,
    parameter SRA = 6'b000011,
    parameter SLLV = 6'b000100,
    parameter SRLV = 6'b000110,
    parameter SRAV = 6'b000111,
    parameter LUI = 6'b001111
) (
    input [31:0] a,
    input [31:0] b,
    input [5:0] aluc,
    output [31:0] r,
    output zero,
    output reg carry,
    output negative,
    output reg overflow,
    output flag
);

    wire [31:0] a_signed, b_signed;
    wire [32:0] res;
    reg [32:0] res_reg;
    assign a_signed = $signed(a);
    assign b_signed = $signed(b);
    assign r = res[31:0];
    assign zero = (res[31:0] == 0);
    assign negative = res[31];
    assign flag = (aluc == SLT || aluc == SLTU) ? ((aluc == SLT) ? ($signed(a) < $signed(b)) : (a < b)) : 1'b0;
    always @(*) begin
        case (aluc)
            ADD: begin
                res_reg = a_signed + b_signed;
                carry = res_reg[32];
                overflow = (~a_signed[31] & ~b_signed[31] & res_reg[31]) | (a_signed[31] & b_signed[31] & ~res_reg[31]);
            end
            ADDU: begin
                res_reg = a + b;
                carry = res_reg[32];
                overflow = 0;
            end
            SUB: begin
                res_reg = a_signed - b_signed;
                carry = res_reg[32];
                overflow = (a_signed[31] & ~b_signed[31] & ~res_reg[31]) | (~a_signed[31] & b_signed[31] & res_reg[31]);
            end
            SUBU: begin
                res_reg = a - b;
                carry = res_reg[32];
                overflow = 0;
            end
            AND: begin
                res_reg = {1'b0, a & b};
                carry = 0;
                overflow = 0;
            end
            OR: begin
                res_reg = {1'b0, a | b};
                carry = 0;
                overflow = 0;
            end
            XOR: begin
                res_reg = {1'b0, a ^ b};
                carry = 0;
                overflow = 0;
            end
            NOR: begin
                res_reg = {1'b0, ~(a | b)};
                carry = 0;
                overflow = 0;
            end
            SLT: begin
                res_reg = {1'b0, ($signed(a) < $signed(b)) ? {31'b0, 1'b1} : 33'b0};
                carry = 0;
                overflow = 0;
            end
            SLTU: begin
                res_reg = {1'b0, (a < b) ? {31'b0, 1'b1} : 33'b0};
                carry = 0;
                overflow = 0;
            end
            SLL: begin
                if (a <= 31) begin
                    res_reg = {1'b0, b << a};
                end else begin
                    res_reg = 33'b0;
                end
                carry = 0;
                overflow = 0;
            end
            SRL: begin
                if (a <= 31) begin
                    res_reg = {1'b0, b >> a};
                end else begin
                    res_reg = 33'b0;
                end
                carry = 0;
                overflow = 0;
            end
            SRA: begin
                if (a <= 31) begin
                    res_reg = {1'b0, $signed(b) >>> a};
                end else begin
                    res_reg = 33'b0;
                end
                carry = 0;
                overflow = 0;
            end
            SLLV: begin
                res_reg = {1'b0, b << a[4:0]};
                carry = 0;
                overflow = 0;
            end
            SRLV: begin
                res_reg = {1'b0, b >> a[4:0]};
                carry = 0;
                overflow = 0;
            end
            SRAV: begin
                res_reg = {1'b0, $signed(b) >>> a[4:0]};
                carry = 0;
                overflow = 0;
            end
            LUI: begin
                res_reg = {1'b0, a[15:0], 16'b0};
                carry = 0;
                overflow = 0;
            end
            default: begin
                res_reg = 33'b0;
                carry = 0;
                overflow = 0;
            end
        endcase
    end
    assign res = res_reg;
endmodule
